/* custom.css - Enhanced styling for the dashboard */

/* Global Styles */
body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background-color: #f8f9fa;
}

/* Header Styling */
.main-header .logo {
  font-weight: bold;
  font-size: 20px;
  padding: 0 15px;
}

/* Sidebar Styling */
.sidebar {
  background-color: #2c3e50;
}

.sidebar-menu li a {
  color: #ecf0f1;
  font-size: 14px;
  font-weight: 500;
  transition: all 0.3s ease;
  padding: 12px 15px;
}

.sidebar-menu li a:hover {
  background-color: #34495e;
  color: #3498db;
  border-left: 4px solid #3498db;
}

.sidebar-menu li.active > a {
  background-color: #3498db;
  color: white;
  border-left: 4px solid #2980b9;
}

/* Box Styling */
.box {
  margin-bottom: 20px;
  border: 1px solid #e3e6f0;
  border-radius: 10px;
  box-shadow: 0 0.15rem 1.75rem 0 rgba(58, 59, 69, 0.15);
  transition: transform 0.2s ease;
}

.box:hover {
  transform: translateY(-5px);
}

.box-header {
  padding: 15px;
  border-bottom: 1px solid #e3e6f0;
  background-color: #f8f9fc;
  border-radius: 10px 10px 0 0;
}

.box-header h3 {
  font-size: 16px;
  font-weight: 600;
  color: #4e73df;
  margin: 0;
}

.box-body {
  padding: 15px;
  background-color: white;
  border-radius: 0 0 10px 10px;
}

/* Value Box Styling */
.info-box {
  border-radius: 8px;
  box-shadow: 0 0.15rem 1.75rem 0 rgba(58, 59, 69, 0.15);
  border: 1px solid #e3e6f0;
}

.info-box-icon {
  border-radius: 8px 0 0 8px;
}

.info-box-content {
  padding: 10px;
}

.info-box-text {
  font-size: 14px;
  color: #6c757d;
  font-weight: 500;
}

.info-box-number {
  font-size: 24px;
  font-weight: 700;
  color: #2c3e50;
}

/* Tab Box Styling */
.nav-tabs-custom {
  border-radius: 10px;
  box-shadow: 0 0.15rem 1.75rem 0 rgba(58, 59, 69, 0.15);
}

.nav-tabs-custom > .nav-tabs > li.active {
  border-top-color: #4e73df;
}

.nav-tabs-custom > .nav-tabs > li > a {
  color: #6c757d;
  font-weight: 500;
}

.nav-tabs-custom > .nav-tabs > li.active > a {
  color: #4e73df;
  font-weight: 600;
}

/* Button Styling */
.btn {
  border-radius: 6px;
  font-weight: 500;
  padding: 8px 20px;
  transition: all 0.3s ease;
}

.btn-primary {
  background-color: #4e73df;
  border-color: #4e73df;
}

.btn-primary:hover {
  background-color: #2e59d9;
  border-color: #2e59d9;
  transform: translateY(-2px);
}

.btn-success {
  background-color: #1cc88a;
  border-color: #1cc88a;
}

.btn-success:hover {
  background-color: #17a673;
  border-color: #17a673;
}

/* Form Control Styling */
.form-control {
  border-radius: 6px;
  border: 1px solid #d1d3e2;
  padding: 10px;
  font-size: 14px;
}

.form-control:focus {
  border-color: #4e73df;
  box-shadow: 0 0 0 0.2rem rgba(78, 115, 223, 0.25);
}

.selectize-input {
  border-radius: 6px !important;
  border: 1px solid #d1d3e2 !important;
  padding: 10px !important;
}

/* DataTable Styling */
.dataTables_wrapper {
  padding: 10px;
  background-color: white;
  border-radius: 8px;
}

table.dataTable {
  border-collapse: collapse !important;
}

table.dataTable tbody tr:hover {
  background-color: #f8f9fc;
}

table.dataTable thead th {
  border-bottom: 2px solid #e3e6f0;
  color: #4e73df;
  font-weight: 600;
}

/* Plotly Chart Container */
.plotly {
  border-radius: 8px;
  overflow: hidden;
}

/* Responsive Design */
@media (max-width: 768px) {
  .main-header .logo {
    font-size: 16px;
  }

  .sidebar {
    width: 250px;
  }

  .box {
    margin-bottom: 15px;
  }

  .info-box {
    margin-bottom: 10px;
  }
}

/* Animation for Loading */
.shiny-progress .progress-text {
  background-color: #4e73df;
  color: white;
  border-radius: 4px;
  padding: 5px 10px;
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb {
  background: #4e73df;
  border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
  background: #2e59d9;
}

/* Tooltip Styling */
.tooltip {
  font-size: 12px;
}

/* Status Colors for Boxes */
.box.box-primary {
  border-top-color: #4e73df;
}

.box.box-success {
  border-top-color: #1cc88a;
}

.box.box-info {
  border-top-color: #36b9cc;
}

.box.box-warning {
  border-top-color: #f6c23e;
}

.box.box-danger {
  border-top-color: #e74a3b;
}
